import { useEffect, useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select } from '@/components/ui/select'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  Gift, Plus, Send, DollarSign, Calendar, CheckCircle, XCircle, Clock, Eye,
  Ban, FileText, User, Briefcase, Building2,
} from 'lucide-react'

interface Offer {
  id: number
  candidate_id: number
  job_id: number
  title: string
  company_name: string
  candidate_name: string
  candidate_email: string
  job_title: string
  recruiter_name: string
  salary: number
  start_date: string
  benefits: string
  status: string
  sent_at: string
  viewed_at: string
  accepted_at: string
  declined_at: string
  decline_reason: string
  created_at: string
}

interface Candidate {
  id: number
  name: string
  email: string
}

interface Job {
  id: number
  title: string
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: React.ElementType }> = {
  draft: { label: 'Draft', variant: 'secondary', icon: Clock },
  sent: { label: 'Sent', variant: 'warning', icon: Send },
  viewed: { label: 'Viewed', variant: 'default', icon: Eye },
  accepted: { label: 'Accepted', variant: 'success', icon: CheckCircle },
  declined: { label: 'Declined', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: Ban },
}

export function RecruiterOffersPage() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [offers, setOffers] = useState<Offer[]>([])
  const [candidates, setCandidates] = useState<Candidate[]>([])
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)
  const [saving, setSaving] = useState(false)
  const [sending, setSending] = useState<number | null>(null)
  const [selectedOffer, setSelectedOffer] = useState<Offer | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [statusFilter, setStatusFilter] = useState('')

  // Form fields
  const [candidateId, setCandidateId] = useState('')
  const [jobId, setJobId] = useState('')
  const [offerTitle, setOfferTitle] = useState('')
  const [salary, setSalary] = useState('')
  const [startDate, setStartDate] = useState('')
  const [benefits, setBenefits] = useState('')

  useEffect(() => {
    loadData()
  }, [])

  // Handle query params for pre-filled offer creation
  useEffect(() => {
    const create = searchParams.get('create')
    const cId = searchParams.get('candidateId')
    const jId = searchParams.get('jobId')
    const cName = searchParams.get('candidateName')

    if (create === '1') {
      if (cId) setCandidateId(cId)
      if (jId) setJobId(jId)
      setShowCreate(true)
      // Clean up URL params
      setSearchParams({}, { replace: true })
    }
  }, [searchParams])

  async function loadData() {
    try {
      const [offersRes, candidatesRes, jobsRes] = await Promise.allSettled([
        apiCall<Offer[]>('/onboarding/offers'),
        apiCall<{ candidates: Candidate[] }>('/recruiter/candidates'),
        apiCall<{ jobs: Job[] }>('/recruiter/jobs'),
      ])
      if (offersRes.status === 'fulfilled') setOffers(Array.isArray(offersRes.value) ? offersRes.value : [])
      if (candidatesRes.status === 'fulfilled') setCandidates(candidatesRes.value.candidates || [])
      if (jobsRes.status === 'fulfilled') setJobs(jobsRes.value.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function createOffer() {
    if (!candidateId || !jobId || !salary) {
      alert('Please fill in candidate, job, and salary')
      return
    }
    setSaving(true)
    try {
      await apiCall('/onboarding/offers', {
        method: 'POST',
        body: {
          candidate_id: Number(candidateId),
          job_id: Number(jobId),
          title: offerTitle || jobs.find(j => j.id === Number(jobId))?.title || 'Job Offer',
          salary: Number(salary),
          start_date: startDate || null,
          benefits,
        },
      })
      setShowCreate(false)
      resetForm()
      loadData()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to create offer')
    } finally {
      setSaving(false)
    }
  }

  async function sendOffer(id: number, e?: React.MouseEvent) {
    e?.stopPropagation()
    setSending(id)
    try {
      await apiCall(`/onboarding/offers/${id}/send`, { method: 'POST' })
      loadData()
      if (selectedOffer?.id === id) {
        setSelectedOffer(prev => prev ? { ...prev, status: 'sent', sent_at: new Date().toISOString() } : null)
      }
    } catch {
      // silent
    } finally {
      setSending(null)
    }
  }

  async function withdrawOffer(id: number) {
    if (!confirm('Are you sure you want to withdraw this offer?')) return
    setWithdrawing(true)
    try {
      await apiCall(`/onboarding/offers/${id}/withdraw`, { method: 'POST' })
      setSelectedOffer(null)
      loadData()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw offer')
    } finally {
      setWithdrawing(false)
    }
  }

  function resetForm() {
    setCandidateId('')
    setJobId('')
    setOfferTitle('')
    setSalary('')
    setStartDate('')
    setBenefits('')
  }

  const allStatuses = ['draft', 'sent', 'viewed', 'accepted', 'declined', 'withdrawn']
  const statusCounts = allStatuses.reduce((acc, s) => {
    acc[s] = offers.filter(o => o.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = offers.filter(o => !statusFilter || o.status === statusFilter)

  const draftOffers = filtered.filter(o => o.status === 'draft')
  const pendingOffers = filtered.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = filtered.filter(o => ['accepted', 'declined', 'withdrawn'].includes(o.status))

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">Offers</h1>
          <p className="text-muted-foreground">Create and manage job offers</p>
        </div>
        <Button onClick={() => setShowCreate(true)} className="gap-2">
          <Plus className="h-4 w-4" /> Create Offer
        </Button>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{offers.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {offers.filter(o => ['sent', 'viewed'].includes(o.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Pending</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {offers.filter(o => o.status === 'accepted').length}
            </p>
            <p className="text-xs text-muted-foreground">Accepted</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-destructive">
              {offers.filter(o => o.status === 'declined').length}
            </p>
            <p className="text-xs text-muted-foreground">Declined</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({offers.length})
        </Button>
        {allStatuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">
              {offers.length === 0 ? 'No offers created yet' : 'No offers match this filter'}
            </p>
            {offers.length === 0 && (
              <Button onClick={() => setShowCreate(true)} className="gap-2">
                <Plus className="h-4 w-4" /> Create Your First Offer
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {/* Draft offers */}
          {draftOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Drafts ({draftOffers.length})
              </h2>
              <div className="space-y-2">
                {draftOffers.map(offer => (
                  <OfferRow
                    key={offer.id}
                    offer={offer}
                    onSend={(e) => sendOffer(offer.id, e)}
                    sending={sending === offer.id}
                    onClick={() => setSelectedOffer(offer)}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Pending */}
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Response ({pendingOffers.length})
              </h2>
              <div className="space-y-2">
                {pendingOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}

          {/* Resolved */}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Resolved ({resolvedOffers.length})
              </h2>
              <div className="space-y-2">
                {resolvedOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Gift className="h-5 w-5 text-primary" />
              Offer Details
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedOffer.status] || { label: selectedOffer.status, variant: 'secondary' as const, icon: Clock }
              const Icon = config.icon
              return (
                <Badge variant={config.variant} className="gap-1 w-fit">
                  <Icon className="h-3 w-3" /> {config.label}
                </Badge>
              )
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <User className="h-3 w-3" /> Candidate
                </p>
                <p className="font-medium">{selectedOffer.candidate_name || 'Unknown'}</p>
                <p className="text-xs text-muted-foreground">{selectedOffer.candidate_email}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Briefcase className="h-3 w-3" /> Position
                </p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <DollarSign className="h-3 w-3" /> Salary
                </p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Start Date
                </p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>

            {/* Benefits */}
            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {/* Timeline */}
            <div className="rounded-lg border p-3 space-y-2">
              <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Timeline</p>
              <div className="space-y-1 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Created</span>
                  <span>{new Date(selectedOffer.created_at).toLocaleDateString()}</span>
                </div>
                {selectedOffer.sent_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Sent</span>
                    <span>{new Date(selectedOffer.sent_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.viewed_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Viewed</span>
                    <span>{new Date(selectedOffer.viewed_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.accepted_at && (
                  <div className="flex justify-between text-emerald-600">
                    <span>Accepted</span>
                    <span>{new Date(selectedOffer.accepted_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.declined_at && (
                  <div className="flex justify-between text-destructive">
                    <span>Declined</span>
                    <span>{new Date(selectedOffer.declined_at).toLocaleDateString()}</span>
                  </div>
                )}
              </div>
            </div>

            {/* Decline reason */}
            {selectedOffer.decline_reason && (
              <div className="rounded-lg bg-destructive/10 p-3">
                <p className="text-xs text-muted-foreground mb-1">Decline Reason</p>
                <p className="text-sm">{selectedOffer.decline_reason}</p>
              </div>
            )}

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              {selectedOffer.status === 'draft' && (
                <>
                  <Button
                    onClick={() => sendOffer(selectedOffer.id)}
                    disabled={sending === selectedOffer.id}
                    className="gap-2 flex-1"
                  >
                    {sending === selectedOffer.id ? (
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                    ) : (
                      <Send className="h-4 w-4" />
                    )}
                    Send to Candidate
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => withdrawOffer(selectedOffer.id)}
                    disabled={withdrawing}
                    className="gap-2"
                  >
                    <Ban className="h-4 w-4" /> Delete
                  </Button>
                </>
              )}
              {['sent', 'viewed'].includes(selectedOffer.status) && (
                <Button
                  variant="outline"
                  onClick={() => withdrawOffer(selectedOffer.id)}
                  disabled={withdrawing}
                  className="gap-2 text-destructive"
                >
                  {withdrawing ? (
                    <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                  ) : (
                    <Ban className="h-4 w-4" />
                  )}
                  Withdraw Offer
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Create offer dialog */}
      <Dialog open={showCreate} onClose={() => { setShowCreate(false); resetForm() }} className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Create New Offer</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div>
            <Label>Candidate *</Label>
            <Select value={candidateId} onChange={e => setCandidateId(e.target.value)} className="mt-1">
              <option value="">Select candidate...</option>
              {candidates.map(c => (
                <option key={c.id} value={c.id}>{c.name} ({c.email})</option>
              ))}
            </Select>
          </div>
          <div>
            <Label>Job Position *</Label>
            <Select value={jobId} onChange={e => setJobId(e.target.value)} className="mt-1">
              <option value="">Select job...</option>
              {jobs.map(j => (
                <option key={j.id} value={j.id}>{j.title}</option>
              ))}
            </Select>
          </div>
          <div>
            <Label>Offer Title</Label>
            <Input
              value={offerTitle}
              onChange={e => setOfferTitle(e.target.value)}
              placeholder="e.g. Senior Engineer Offer"
              className="mt-1"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Annual Salary ($) *</Label>
              <Input
                type="number"
                value={salary}
                onChange={e => setSalary(e.target.value)}
                placeholder="e.g. 120000"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Start Date</Label>
              <Input
                type="date"
                value={startDate}
                onChange={e => setStartDate(e.target.value)}
                className="mt-1"
              />
            </div>
          </div>
          <div>
            <Label>Benefits</Label>
            <Textarea
              value={benefits}
              onChange={e => setBenefits(e.target.value)}
              placeholder="Health insurance, 401k, PTO, etc..."
              rows={3}
              className="mt-1"
            />
          </div>
          <div className="flex gap-2 pt-2">
            <Button onClick={createOffer} disabled={saving} className="gap-2">
              {saving ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <Gift className="h-4 w-4" />
              )}
              Create Offer
            </Button>
            <Button variant="outline" onClick={() => { setShowCreate(false); resetForm() }}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferRow({ offer, onSend, sending, onClick }: {
  offer: Offer
  onSend?: (e: React.MouseEvent) => void
  sending?: boolean
  onClick?: () => void
}) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
  const Icon = config.icon

  return (
    <Card className="cursor-pointer transition-shadow hover:shadow-md" onClick={onClick}>
      <CardContent className="p-4">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <div className="min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{offer.candidate_name || 'Unknown'}</h3>
              <Badge variant={config.variant} className="gap-1">
                <Icon className="h-3 w-3" /> {config.label}
              </Badge>
            </div>
            <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
              <span className="flex items-center gap-1">
                <Briefcase className="h-3 w-3" />
                {offer.job_title || offer.title}
              </span>
              <span className="flex items-center gap-1">
                <DollarSign className="h-3 w-3" />
                ${Number(offer.salary).toLocaleString()}/yr
              </span>
              {offer.start_date && (
                <span className="flex items-center gap-1">
                  <Calendar className="h-3 w-3" />
                  Start: {new Date(offer.start_date).toLocaleDateString()}
                </span>
              )}
              {offer.decline_reason && (
                <span className="text-destructive">Reason: {offer.decline_reason}</span>
              )}
            </div>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {offer.status === 'draft' && onSend && (
              <Button size="sm" onClick={onSend} disabled={sending} className="gap-1">
                {sending ? (
                  <div className="h-3 w-3 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <Send className="h-3 w-3" />
                )}
                Send
              </Button>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  Gift, DollarSign, Calendar, Building2, CheckCircle, XCircle, Clock, Eye,
} from 'lucide-react'

interface Offer {
  id: number
  title: string
  company_name: string
  company?: string
  job_title: string
  salary: number
  start_date: string
  benefits: string
  status: string
  sent_at: string
  viewed_at: string
  accepted_at: string
  declined_at: string
  decline_reason: string
  created_at: string
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: React.ElementType }> = {
  draft: { label: 'Draft', variant: 'secondary', icon: Clock },
  sent: { label: 'Pending', variant: 'warning', icon: Clock },
  viewed: { label: 'Viewed', variant: 'default', icon: Eye },
  accepted: { label: 'Accepted', variant: 'success', icon: CheckCircle },
  declined: { label: 'Declined', variant: 'destructive', icon: XCircle },
}

export function CandidateOffersPage() {
  const [offers, setOffers] = useState<Offer[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedOffer, setSelectedOffer] = useState<Offer | null>(null)
  const [declineDialog, setDeclineDialog] = useState(false)
  const [declineReason, setDeclineReason] = useState('')
  const [acting, setActing] = useState(false)

  useEffect(() => {
    loadOffers()
  }, [])

  async function loadOffers() {
    try {
      const data = await apiCall<Offer[]>('/onboarding/offers/me')
      setOffers(Array.isArray(data) ? data : [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function markViewed(offer: Offer) {
    if (!offer.viewed_at) {
      try {
        await apiCall(`/onboarding/offers/${offer.id}/view`, { method: 'POST' })
      } catch {
        // silent
      }
    }
    setSelectedOffer(offer)
  }

  async function acceptOffer() {
    if (!selectedOffer) return
    setActing(true)
    try {
      await apiCall(`/onboarding/offers/${selectedOffer.id}/accept`, { method: 'POST' })
      setSelectedOffer(null)
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to accept offer')
    } finally {
      setActing(false)
    }
  }

  async function declineOffer() {
    if (!selectedOffer) return
    setActing(true)
    try {
      await apiCall(`/onboarding/offers/${selectedOffer.id}/decline`, {
        method: 'POST',
        body: { decline_reason: declineReason },
      })
      setDeclineDialog(false)
      setSelectedOffer(null)
      setDeclineReason('')
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to decline offer')
    } finally {
      setActing(false)
    }
  }

  const pendingOffers = offers.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = offers.filter(o => ['accepted', 'declined'].includes(o.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Offers</h1>
        <p className="text-muted-foreground">Review and respond to job offers</p>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : offers.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No offers yet</p>
            <p className="text-sm text-muted-foreground mt-1">When a recruiter makes you an offer, it will appear here</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Offers ({pendingOffers.length})
              </h2>
              <div className="space-y-3">
                {pendingOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => markViewed(offer)} />
                ))}
              </div>
            </div>
          )}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Past Offers</h2>
              <div className="space-y-3">
                {resolvedOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && !declineDialog && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedOffer.title || selectedOffer.job_title}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Company</p>
                <p className="font-medium">{selectedOffer.company_name || selectedOffer.company}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Position</p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Salary</p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Start Date</p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>
            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {['sent', 'viewed'].includes(selectedOffer.status) && (
              <div className="flex gap-2 pt-2">
                <Button onClick={acceptOffer} disabled={acting} className="flex-1 gap-2">
                  <CheckCircle className="h-4 w-4" /> Accept Offer
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setDeclineDialog(true)}
                  disabled={acting}
                  className="flex-1 gap-2"
                >
                  <XCircle className="h-4 w-4" /> Decline
                </Button>
              </div>
            )}

            {selectedOffer.status === 'accepted' && (
              <Badge variant="success" className="w-full justify-center py-2 text-sm">
                <CheckCircle className="h-4 w-4 mr-1" /> You accepted this offer
              </Badge>
            )}
            {selectedOffer.status === 'declined' && (
              <div>
                <Badge variant="destructive" className="w-full justify-center py-2 text-sm">
                  <XCircle className="h-4 w-4 mr-1" /> You declined this offer
                </Badge>
                {selectedOffer.decline_reason && (
                  <p className="text-sm text-muted-foreground mt-2">Reason: {selectedOffer.decline_reason}</p>
                )}
              </div>
            )}
          </div>
        </Dialog>
      )}

      {/* Decline reason dialog */}
      <Dialog open={declineDialog} onClose={() => setDeclineDialog(false)}>
        <DialogHeader>
          <DialogTitle>Decline Offer</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Are you sure you want to decline this offer? Please provide a reason (optional).
          </p>
          <Textarea
            placeholder="Reason for declining..."
            value={declineReason}
            onChange={e => setDeclineReason(e.target.value)}
            rows={3}
          />
          <div className="flex gap-2">
            <Button variant="destructive" onClick={declineOffer} disabled={acting} className="gap-2">
              {acting ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <XCircle className="h-4 w-4" />
              )}
              Confirm Decline
            </Button>
            <Button variant="outline" onClick={() => setDeclineDialog(false)}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferCard({ offer, onClick }: { offer: Offer; onClick: () => void }) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
